<?php declare(strict_types=1);
namespace MOJ\JudicialSystem;
use PDO;use Psr\Log\LoggerInterface;
final class Importer{private LoggerInterface $log;public function __construct(private MojApi $api=new MojApi(),private Parser $parser=new Parser(),private PDO $db=new \PDO('sqlite::memory:')){$this->db=$db instanceof \PDO && $db->getAttribute(\PDO::ATTR_DRIVER_NAME)==='sqlite'?Database::connect():$db;$this->log=Logger::channel('import');} public function run(array $filters=[],int $limitPages=0):array{$page=1;$imported=0;$updated=0;$errors=0;do{$payload=$filters+['pageNumber'=>$page,'pageSize'=>50];$list=$this->api->judgementsList($payload);$items=$list['items']??$list['data']??$list['result']??[];foreach($items as $item){try{$id=(string)($item['id']??$item['judgementId']??$item['decisionId']??'');$detail=$id!==''?$this->api->details($id):$item;$parsed=$this->parser->decision($detail+$item);$updated += $this->save($parsed)?0:1;$imported++;}catch(\Throwable $e){$errors++;$this->log->error('item_failed',['error'=>$e->getMessage(),'item'=>$item]);}}$totalPages=(int)($list['totalPages']??$list['pages']??$page);$this->log->info('page_done',compact('page','imported','updated','errors'));$page++;}while($page<=$totalPages && ($limitPages===0 || $page<=$limitPages));return compact('imported','updated','errors');} private function save(array $d):bool{$sql='INSERT INTO judicial_decisions (external_id,decision_number,title,court_name,court_type,circuit,judge_name,decision_date,subject,summary,full_text,source_url,content_hash,raw_json) VALUES (:external_id,:decision_number,:title,:court,:court_type,:circuit,:judge,:decision_date,:subject,:summary,:full_text,:source_url,:content_hash,:raw_json) ON DUPLICATE KEY UPDATE title=VALUES(title),court_name=VALUES(court_name),full_text=VALUES(full_text),content_hash=VALUES(content_hash),raw_json=VALUES(raw_json),updated_at=CURRENT_TIMESTAMP';$st=$this->db->prepare($sql);$st->execute($d);return $st->rowCount()===1;}}
